-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "العبادات" (ibadat) — تستنفد العنقود بالكامل (10 تصنيفات فرعية
-- بلا محتوى من أصل 11: الطهارة، الجنائز، الزكاة، الصيام، الاعتكاف،
-- الحج والعمرة، الأضحية، النذر والأيمان، الأطعمة والأشربة، اللباس
-- والزينة). التصنيف الحادي عشر (الصلاة) كان منشوراً مسبقاً.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: فقه السنة لسيد
-- سابق، المغني لابن قدامة، الشرح الممتع لابن عثيمين، بداية المجتهد
-- لابن رشد، فقه الزكاة للقرضاوي.
-- كل آية استُشهد بها (المائدة:6، آل عمران:185، البقرة:43، التوبة:103،
-- البقرة:183، البقرة:187، آل عمران:97، الكوثر:2، المائدة:89، المائدة:3،
-- الأعراف:26) تحقَّقت حرفياً من artifacts/majalis/public/data/quran
-- محلياً عبر حقل numberInSurah قبل الإدراج.
-- كل حديث مستشهَد به (9 أحاديث) متحقَّق حرفياً عبر WebSearch قبل
-- الإدراج، وكلها من الصحيحين أو متفق عليه أو مسلم منفرداً: «بني
-- الإسلام على خمس» (مسلم 16، ابن عمر)، «اغسلنها ثلاثاً أو خمساً»
-- (متفق عليه، أم عطية)، «من صام رمضان إيماناً واحتساباً غفر له ما
-- تقدم من ذنبه» (البخاري 38، أبو هريرة)، «كان يعتكف العشر الأواخر من
-- رمضان حتى توفاه الله» (متفق عليه، عائشة)، «من حج فلم يرفث ولم يفسق
-- رجع كيوم ولدته أمه» (البخاري 1521، مسلم 1350، أبو هريرة)، «ضحى
-- بكبشين أملحين أقرنين ذبحهما بيده» (البخاري 5565، مسلم 1966، أنس بن
-- مالك)، «من نذر أن يطيع الله فليطعه» (البخاري، عائشة)، «كل ذي ناب من
-- السباع فأكله حرام» (مسلم 1933، أبو هريرة)، «لا ينظر الله إلى من جر
-- ثوبه خيلاء» (البخاري 5783، متفق عليه، ابن عمر).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات العشرة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الطهارة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='eb3a6c8b-cc6b-46da-acd3-854cdf996131' AND title='تعريف الطهارة وأقسامها وأصل مشروعية الوضوء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الطهارة وأقسامها وأصل مشروعية الوضوء', 'معنى الطهارة وأقسامها (طهارة حدث وطهارة خبث) وأصل مشروعية الوضوء من القرآن', 'eb3a6c8b-cc6b-46da-acd3-854cdf996131', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأقسامها', 'الطهارة لغة: النظافة والنزاهة عن الأقذار، واصطلاحاً: رفع الحدث وإزالة النجس. وهي قسمان: طهارة حدث (كالوضوء والغسل والتيمم) وطهارة خبث (إزالة النجاسة عن البدن والثوب والمكان)، وهي شرط لصحة الصلاة لا تصح بدونها إلا لعذر، ولذلك أفردها الفقهاء بالذكر أول أبواب الفقه لأنها مقدمة العبادة.', 1),
    (v_lesson, 'evidence', 'أصل الوضوء من القرآن', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ وَامْسَحُوا بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى الْكَعْبَيْنِ﴾ (المائدة: 6)، وهذه الآية هي الأصل القرآني المفصِّل لأعضاء الوضوء الأربعة، وقد بيّنت السنة صفة أدائها وسننها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق', 1);
  END IF;

  -- 2) الجنائز
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='51f69950-a718-407f-b40a-74b11badcf54' AND title='حكم غسل الميت وصفته وفرضية تجهيز الجنازة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم غسل الميت وصفته وفرضية تجهيز الجنازة', 'حكم تجهيز الميت من غسل وتكفين وصلاة ودفن، وصفة الغسل الواردة في السنة', '51f69950-a718-407f-b40a-74b11badcf54', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تجهيز الميت فرض كفاية', 'تجهيز الميت المسلم من غسل وتكفين والصلاة عليه ودفنه فرض كفاية على المسلمين، إذا قام به من يكفي سقط الإثم عن الباقين، وقد بيّنت السنة صفة الغسل وأنه يكون بالماء والسدر وترًا (ثلاثاً أو خمساً)، وهذا التذكير بالموت من مقاصد باب الجنائز في تربية القلب على الاستعداد للآخرة.', 1),
    (v_lesson, 'evidence', 'أصل التذكير بالموت وصفة الغسل', 'قال تعالى: ﴿كُلُّ نَفْسٍ ذَائِقَةُ الْمَوْتِ وَإِنَّمَا تُوَفَّوْنَ أُجُورَكُمْ يَوْمَ الْقِيَامَةِ﴾ (آل عمران: 185)، وعن أم عطية رضي الله عنها قالت: دخل علينا رسول الله صلى الله عليه وسلم ونحن نغسل ابنته، فقال: «اغْسِلْنَهَا ثَلَاثًا، أَوْ خَمْسًا، أَوْ أَكْثَرَ مِنْ ذَلِكَ، بِمَاءٍ وَسِدْرٍ، وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا» متفق عليه، فبيّن هذا الحديث صفة غسل الميت المشروعة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الجنائز)', 1);
  END IF;

  -- 3) الزكاة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0952fe6c-55dd-4b4c-9051-463ad41f3ccd' AND title='الزكاة ركن من أركان الإسلام وأصل فرضيتها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الزكاة ركن من أركان الإسلام وأصل فرضيتها', 'مكانة الزكاة بوصفها ركناً من أركان الإسلام الخمسة وأصل فرضيتها من القرآن والسنة', '0952fe6c-55dd-4b4c-9051-463ad41f3ccd', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومكانتها', 'الزكاة لغة: النماء والزيادة والتطهير، واصطلاحاً: حق واجب في مال مخصوص لطائفة مخصوصة في وقت مخصوص. وهي الركن الثالث من أركان الإسلام، فرضها الله على من ملك نصاباً من المال وحال عليه الحول، وقد قرنها القرآن بالصلاة في نحو ثمانية وعشرين موضعاً، مما يدل على وثيق ارتباطها بها في الأهمية والمكانة.', 1),
    (v_lesson, 'evidence', 'أصلها المقترن بالصلاة وحديث الأركان', 'قال تعالى: ﴿وَأَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ وَارْكَعُوا مَعَ الرَّاكِعِينَ﴾ (البقرة: 43)، وعن ابن عمر رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ: شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَإِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَحَجِّ الْبَيْتِ، وَصَوْمِ رَمَضَانَ» رواه مسلم، فذكر إيتاء الزكاة ضمن الأركان الخمسة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه الزكاة — الدكتور يوسف القرضاوي', 1);
  END IF;

  -- 4) الصيام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='e69a73b0-9235-4df5-aa8b-492833ca44eb' AND title='فرضية صيام رمضان وفضل صيامه إيماناً واحتساباً') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فرضية صيام رمضان وفضل صيامه إيماناً واحتساباً', 'أصل فرضية صيام رمضان من القرآن وفضل صيامه بإيمان واحتساب في مغفرة الذنوب', 'e69a73b0-9235-4df5-aa8b-492833ca44eb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وفرضيته', 'الصيام لغة: الإمساك، واصطلاحاً: الإمساك عن المفطرات من طلوع الفجر إلى غروب الشمس بنية التعبد لله تعالى. وصيام شهر رمضان فرض عين على كل مسلم مكلف قادر، فُرض في السنة الثانية للهجرة، وهو الركن الرابع من أركان الإسلام.', 1),
    (v_lesson, 'evidence', 'أصل الفرضية وفضل الاحتساب', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِنْ قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ﴾ (البقرة: 183)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا، غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ» رواه البخاري، وفي هذا بيان أن الأجر منوط بالإيمان بفرضيته واحتساب الأجر عند الله لا بمجرد الإمساك.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الشرح الممتع على زاد المستقنع — الشيخ محمد بن صالح العثيمين', 1);
  END IF;

  -- 5) الاعتكاف
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d1fdb38e-8578-4383-8c6f-f13697004e85' AND title='تعريف الاعتكاف ومشروعيته في العشر الأواخر من رمضان') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الاعتكاف ومشروعيته في العشر الأواخر من رمضان', 'تعريف الاعتكاف وحكمه وأصل مشروعيته بملازمة النبي له في العشر الأواخر من رمضان', 'd1fdb38e-8578-4383-8c6f-f13697004e85', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وحكمه', 'الاعتكاف لغة: لزوم الشيء وحبس النفس عليه، واصطلاحاً: لزوم مسجد لطاعة الله تعالى على صفة مخصوصة بنية التقرب إليه. وهو سنة مؤكدة في حق الرجال والنساء، ويتأكد استحبابه في العشر الأواخر من رمضان طلباً لليلة القدر، ولا يصح إلا في مسجد تُقام فيه الجماعة عند جمهور الفقهاء.', 1),
    (v_lesson, 'evidence', 'أصله من القرآن وملازمة النبي له', 'قال تعالى: ﴿وَلَا تُبَاشِرُوهُنَّ وَأَنْتُمْ عَاكِفُونَ فِي الْمَسَاجِدِ﴾ (البقرة: 187)، وهذه الآية تثبت مشروعية الاعتكاف في المساجد. وعن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم «كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ حَتَّى تَوَفَّاهُ اللَّهُ عَزَّ وَجَلَّ، ثُمَّ اعْتَكَفَ أَزْوَاجُهُ مِنْ بَعْدِهِ» متفق عليه، فداوم عليه صلى الله عليه وسلم حتى وفاته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الاعتكاف)', 1);
  END IF;

  -- 6) الحج والعمرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2eab838c-b807-4a1e-ba44-3cdf2a3de0a7' AND title='فرضية الحج على المستطيع وفضل الحج المبرور') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فرضية الحج على المستطيع وفضل الحج المبرور', 'أصل فرضية الحج مرة في العمر على المستطيع، وفضل الحج المبرور في تكفير الذنوب', '2eab838c-b807-4a1e-ba44-3cdf2a3de0a7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وشرط وجوبه', 'الحج لغة: القصد، واصطلاحاً: قصد بيت الله الحرام لأداء نسك مخصوص في زمن مخصوص. وهو الركن الخامس من أركان الإسلام، يجب مرة واحدة في العمر على كل مسلم بالغ عاقل مستطيع بدنياً ومالياً، والاستطاعة شرط في وجوبه لا في أصل مشروعيته.', 1),
    (v_lesson, 'evidence', 'أصل الفرضية وفضل الحج المبرور', 'قال تعالى: ﴿وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنِ اسْتَطَاعَ إِلَيْهِ سَبِيلًا﴾ (آل عمران: 97)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ حَجَّ لِلَّهِ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ» متفق عليه، وفي هذا بيان عظيم فضل الحج الخالص المبرور من الرفث والفسوق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بداية المجتهد ونهاية المقتصد — القاضي أبو الوليد ابن رشد', 1);
  END IF;

  -- 7) الأضحية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f06e4103-6d8e-4c21-9a86-80f751ee5ea2' AND title='حكم الأضحية ومشروعيتها في القرآن والسنة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الأضحية ومشروعيتها في القرآن والسنة', 'تعريف الأضحية وحكمها عند الفقهاء وأصل مشروعيتها من فعل النبي صلى الله عليه وسلم', 'f06e4103-6d8e-4c21-9a86-80f751ee5ea2', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وحكمها', 'الأضحية: ما يُذبح من بهيمة الأنعام تقرباً إلى الله تعالى في أيام النحر ابتداءً من يوم عيد الأضحى. وهي سنة مؤكدة عند جمهور الفقهاء، وذهب بعضهم إلى وجوبها على القادر، ووقتها من بعد صلاة العيد إلى غروب شمس آخر أيام التشريق.', 1),
    (v_lesson, 'evidence', 'أصلها من القرآن وفعل النبي', 'قال تعالى: ﴿فَصَلِّ لِرَبِّكَ وَانْحَرْ﴾ (الكوثر: 2)، وعن أنس بن مالك رضي الله عنه أن النبي صلى الله عليه وسلم «ضَحَّى بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ، ذَبَحَهُمَا بِيَدِهِ، وَسَمَّى وَكَبَّرَ» متفق عليه، وهذا أصل السنة في صفة الذبح ومباشرة المضحي له بنفسه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق', 1);
  END IF;

  -- 8) النذر والأيمان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='116b0b9c-86ef-4295-b0fe-a64433db2053' AND title='حكم الوفاء بالنذر وكفارة اليمين المنعقدة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الوفاء بالنذر وكفارة اليمين المنعقدة', 'تعريف النذر واليمين ووجوب الوفاء بنذر الطاعة، وأصل مشروعية كفارة اليمين', '116b0b9c-86ef-4295-b0fe-a64433db2053', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما وحكمهما', 'النذر: إلزام المكلف نفسه بشيء غير واجب أصلاً تقرباً إلى الله تعالى. واليمين: تأكيد أمر أو منعه بذكر اسم الله تعالى أو صفة من صفاته. ونذر الطاعة يجب الوفاء به، ونذر المعصية يحرم الوفاء به وتلزم فيه كفارة يمين، واليمين المنعقدة إذا حُنث فيها وجبت كفارتها المذكورة في القرآن.', 1),
    (v_lesson, 'evidence', 'أصل كفارة اليمين ووجوب الوفاء بالنذر', 'قال تعالى: ﴿لَا يُؤَاخِذُكُمُ اللَّهُ بِاللَّغْوِ فِي أَيْمَانِكُمْ وَلَكِنْ يُؤَاخِذُكُمْ بِمَا عَقَّدْتُمُ الْأَيْمَانَ فَكَفَّارَتُهُ إِطْعَامُ عَشَرَةِ مَسَاكِينَ﴾ (المائدة: 89)، وعن عائشة رضي الله عنها أن رسول الله صلى الله عليه وسلم قال: «مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ، وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ» رواه البخاري.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب النذور والأيمان)', 1);
  END IF;

  -- 9) الأطعمة والأشربة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='45a3199a-9046-473c-bbe0-dac35fb7082f' AND title='الأصل في الأطعمة الإباحة وضوابط المحرَّم منها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأصل في الأطعمة الإباحة وضوابط المحرَّم منها', 'القاعدة الفقهية في إباحة الأطعمة أصلاً، وذكر المحرَّم منها في القرآن والسنة', '45a3199a-9046-473c-bbe0-dac35fb7082f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'القاعدة الأصلية والمحرَّم منها', 'الأصل في الأطعمة والأشربة الإباحة والحل، فلا يحرم منها إلا ما ورد نص بتحريمه، لقاعدة أن الأصل في الأشياء الإباحة حتى يقوم دليل التحريم. وقد ذكر القرآن المحرمات الأصلية من الميتة والدم ولحم الخنزير، وبيّنت السنة تحريم كل ذي ناب من السباع وكل ذي مخلب من الطير.', 1),
    (v_lesson, 'evidence', 'المحرمات المنصوصة في القرآن والسنة', 'قال تعالى: ﴿حُرِّمَتْ عَلَيْكُمُ الْمَيْتَةُ وَالدَّمُ وَلَحْمُ الْخِنْزِيرِ وَمَا أُهِلَّ لِغَيْرِ اللَّهِ بِهِ﴾ (المائدة: 3)، وعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «كُلُّ ذِي نَابٍ مِنَ السِّبَاعِ فَأَكْلُهُ حَرَامٌ» رواه مسلم، فألحقت السنة هذا النوع بالمحرمات المذكورة في القرآن.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الأطعمة)', 1);
  END IF;

  -- 10) اللباس والزينة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='584510ee-759c-4ea0-8f4e-0a22f89a6003' AND title='ضوابط اللباس والزينة والنهي عن الإسبال خيلاء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ضوابط اللباس والزينة والنهي عن الإسبال خيلاء', 'أصل مشروعية اللباس والزينة في القرآن، وضابط النهي عن إسبال الثوب على وجه الكبر', '584510ee-759c-4ea0-8f4e-0a22f89a6003', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أصل مشروعيته وضوابطه', 'اللباس نعمة من الله سترًا للعورة وزينة للبدن، والأصل فيه الإباحة ما لم يخالف ضابطاً شرعياً كستر العورة وعدم التشبه بالجنس الآخر وعدم الإسبال على وجه الخيلاء والكبر، وقد نهت السنة خصوصاً عن جر الثوب أسفل الكعبين تكبراً لما فيه من مخالفة هدي التواضع.', 1),
    (v_lesson, 'evidence', 'أصل النعمة والنهي عن الخيلاء', 'قال تعالى: ﴿يَا بَنِي آدَمَ قَدْ أَنْزَلْنَا عَلَيْكُمْ لِبَاسًا يُوَارِي سَوْآتِكُمْ وَرِيشًا وَلِبَاسُ التَّقْوَى ذَلِكَ خَيْرٌ﴾ (الأعراف: 26)، وعن عبد الله بن عمر رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «لَا يَنْظُرُ اللَّهُ إِلَى مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ» متفق عليه، فقيّدت السنة النهي بقصد الخيلاء والتكبر لا بمطلق طول الثوب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السنة — السيد سابق', 1);
  END IF;

